code = """import json
import ast

# Load data
file_path = locals()['var_function-call-11487107731162164060']
with open(file_path, 'r') as f:
    businesses = json.load(f)

count = 0
for b in businesses:
    attrs = b.get('attributes')
    if not attrs or attrs == 'None':
        continue
    
    # Check BikeParking
    bike_parking = False
    if 'BikeParking' in attrs:
        # It's a string 'True' or 'False'
        if attrs['BikeParking'] == 'True':
            bike_parking = True
            
    # Check BusinessParking
    biz_parking = False
    if 'BusinessParking' in attrs:
        bp_val = attrs['BusinessParking']
        if bp_val and bp_val != 'None':
            try:
                # The string is like "{'garage': False, ...}"
                # This is a Python dict string representation.
                bp_dict = ast.literal_eval(bp_val)
                if isinstance(bp_dict, dict):
                    # Check if any value is True
                    if any(bp_dict.values()):
                        biz_parking = True
            except:
                pass
                
    if bike_parking or biz_parking:
        count += 1

print('__RESULT__:')
print(count)"""

